import{Logger}from '../shared/logger.js';class NotificationBell{constructor(){this.notifications=[];this.unreadCount=0;this.isOpen=false;this.maxNotifications=20;this.init();}init(){this.loadNotifications();this.createBell();this.bindEvents();this.startPolling();}loadNotifications(){const stored=localStorage.getItem('sadec-notifications');if(stored){this.notifications=JSON.parse(stored);this.unreadCount=this.notifications.filter(n=>!n.read).length;}}saveNotifications(){localStorage.setItem('sadec-notifications',JSON.stringify(this.notifications));this.updateBadge();}createBell(){const bell=document.createElement('div');bell.id='notification-bell';bell.className='notification-bell';bell.setAttribute('role','button');bell.setAttribute('aria-label','Notifications');bell.setAttribute('aria-haspopup','true');bell.innerHTML=`<div class="notification-bell-icon"><span class="material-symbols-outlined">notifications</span><span class="notification-badge" ${this.unreadCount===0 ? 'hidden' : ''}>${this.unreadCount>9 ? '9+' : this.unreadCount}</span></div><div class="notification-panel" hidden><div class="notification-panel-header"><h3>Thông báo</h3><div class="notification-actions"><button class="mark-all-read-btn" aria-label="Mark all as read"><span class="material-symbols-outlined">done_all</span></button><button class="clear-all-btn" aria-label="Clear all"><span class="material-symbols-outlined">delete_sweep</span></button></div></div><div class="notification-panel-content"><div class="notification-list"></div><div class="notification-empty" hidden><span class="material-symbols-outlined">notifications_none</span><p>Không có thông báo nào</p></div></div><div class="notification-panel-footer"><a href="/admin/notifications.html">Xem tất cả →</a></div></div>`;const header=document.querySelector('.header-section')||document.querySelector('header');if(header){const searchGlass=header.querySelector('.search-glass');if(searchGlass){searchGlass.after(bell);}else{header.querySelector('div:last-child').after(bell);}}else{document.body.appendChild(bell);}this.bell=bell;this.panel=bell.querySelector('.notification-panel');this.list=bell.querySelector('.notification-list');this.emptyState=bell.querySelector('.notification-empty');this.badge=bell.querySelector('.notification-badge');}bindEvents(){this.bell.addEventListener('click',(e)=>{e.stopPropagation();this.toggle();});document.addEventListener('click',()=>{this.close();});this.bell.querySelector('.mark-all-read-btn').addEventListener('click',(e)=>{e.stopPropagation();this.markAllAsRead();});this.bell.querySelector('.clear-all-btn').addEventListener('click',(e)=>{e.stopPropagation();this.clearAll();});document.addEventListener('keydown',(e)=>{if(e.key==='Escape'&&this.isOpen){this.close();}});}toggle(){if(this.isOpen){this.close();}else{this.open();}}open(){this.isOpen=true;this.panel.hidden=false;this.bell.classList.add('open');this.render();document.body.style.overflow='hidden';}close(){this.isOpen=false;this.panel.hidden=true;this.bell.classList.remove('open');document.body.style.overflow='';}render(){if(this.notifications.length===0){this.list.innerHTML='';this.emptyState.hidden=false;return;}this.emptyState.hidden=true;const recentNotifications=this.notifications.slice(0,this.maxNotifications);this.list.innerHTML=recentNotifications.map((notif,index)=>`<div class="notification-item ${!notif.read ? 'unread' : ''}" data-index="${index}"><div class="notification-icon ${notif.type}"><span class="material-symbols-outlined">${this.getIconForType(notif.type)}</span></div><div class="notification-content"><div class="notification-title">${notif.title}</div><div class="notification-message">${notif.message}</div><div class="notification-time">${this.formatTime(notif.timestamp)}</div></div><button class="notification-dismiss" aria-label="Dismiss notification"><span class="material-symbols-outlined">close</span></button></div>`).join('');this.list.querySelectorAll('.notification-dismiss').forEach((btn,index)=>{btn.addEventListener('click',(e)=>{e.stopPropagation();this.dismiss(index);});});this.list.querySelectorAll('.notification-item').forEach((item,index)=>{item.addEventListener('click',()=>{this.markAsRead(index);});});}getIconForType(type){const icons={'info': 'info','success': 'check_circle','warning': 'warning','error': 'error','lead': 'person_add','campaign': 'campaign','finance': 'attach_money','system': 'settings'};return icons[type]||'notifications';}formatTime(timestamp){const date=new Date(timestamp);const now=new Date();const diffMs=now-date;const diffMins=Math.floor(diffMs/60000);const diffHours=Math.floor(diffMs/3600000);const diffDays=Math.floor(diffMs/86400000);if(diffMins<1)return 'Vừa xong';if(diffMins<60)return `${diffMins}phút trước`;if(diffHours<24)return `${diffHours}giờ trước`;if(diffDays<7)return `${diffDays}ngày trước`;return date.toLocaleDateString('vi-VN',{day: 'numeric',month: 'short'});}add(notification){const newNotif={id: Date.now().toString(),type: notification.type||'info',title: notification.title,message: notification.message,timestamp: Date.now(),read: false,action: notification.action};this.notifications.unshift(newNotif);if(this.notifications.length>this.maxNotifications*2){this.notifications=this.notifications.slice(0,this.maxNotifications*2);}this.unreadCount++;this.saveNotifications();if(!this.isOpen){this.showToast(newNotif);}return newNotif;}dismiss(index){this.notifications.splice(index,1);this.saveNotifications();this.render();}markAsRead(index){if(this.notifications[index]&&!this.notifications[index].read){this.notifications[index].read=true;this.unreadCount=Math.max(0,this.unreadCount-1);this.saveNotifications();this.render();}}markAllAsRead(){this.notifications.forEach(n=>n.read=true);this.unreadCount=0;this.saveNotifications();this.render();}clearAll(){this.notifications=[];this.unreadCount=0;this.saveNotifications();this.render();}updateBadge(){if(this.badge){this.badge.textContent=this.unreadCount>9 ? '9+' : this.unreadCount;this.badge.hidden=this.unreadCount===0;}}showToast(notification){const toast=document.createElement('div');toast.className=`toast toast-${notification.type}`;toast.innerHTML=`<span class="material-symbols-outlined">${this.getIconForType(notification.type)}</span><div><strong>${notification.title}</strong><p>${notification.message}</p></div><button class="toast-dismiss"><span class="material-symbols-outlined">close</span></button>`;toast.addEventListener('click',()=>{toast.remove();if(notification.action){window.location.href=notification.action.url;}});toast.querySelector('.toast-dismiss').addEventListener('click',(e)=>{e.stopPropagation();toast.remove();});document.body.appendChild(toast);setTimeout(()=>{toast.style.opacity='0';setTimeout(()=>toast.remove(),300);},5000);}startPolling(){}async fetchFromAPI(){try{}catch(error){Logger.error('Failed to fetch notifications:',error);}}}if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>{window.notificationBell=new NotificationBell();});}else{window.notificationBell=new NotificationBell();}export{NotificationBell};